// C3: Physical sensing components
instance HokuyoUST10LXLiDAR : DTDFVocab:SensingComponent [
    base:desc "Hokuyo UST-10LX LiDAR providing 2‑D distance measurements for obstacle detection"
    DTDFVocab:producedData LiDARPointCloudTransmitted
]

instance IntelDeepsenseD435iDepthCamera : DTDFVocab:SensingComponent [
    base:desc "Intel Deepsense D435i depth camera supplying synchronized RGB‑D streams for scene understanding"
    DTDFVocab:producedData DepthCameraRGBDTransmitted
]

// C4: Physical‑to‑virtual interaction (Data Transmitted)
instance LiDARPointCloudTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HokuyoUST10LXLiDAR
]

instance DepthCameraRGBDTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom IntelDeepsenseD435iDepthCamera
]

// C5: Data objects derived from transmitted data
instance LiDARPointCloudData : DTDFVocab:Data [
    base:desc "Raw LiDAR point‑cloud data streamed continuously for clustering and tracking"
    DTDFVocab:fromData LiDARPointCloudTransmitted
    DTDFVocab:inputTo ROS2DDSMiddlewareEnabler
]

instance DepthCameraRGBDData : DTDFVocab:Data [
    base:desc "Raw RGB‑D data from depth camera used for scene understanding and sensor fusion"
    DTDFVocab:fromData DepthCameraRGBDTransmitted
    DTDFVocab:inputTo ROS2DDSMiddlewareEnabler
]

// C11: Enablers (tooling & middleware)
instance ROS2DDSMiddlewareEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 middleware with DDS transport enabling real‑time, low‑latency data exchange between physical twin and digital twin"
    DTDFVocab:enables DataMonitoringService, RemoteManagementService
]

instance CloudACCComputeEnabler : DTDFVocab:Enabler [
    base:desc "Cloud compute resources that host the Adaptive Cruise Control (ACC) algorithm offloaded from the vehicle"
    DTDFVocab:enables ComputationOffloadingService
]

instance NVIDIAJetpackGPUEnabler : DTDFVocab:Enabler [
    base:desc "NVIDIA Jetpack 5.0 SDK providing GPU‑accelerated processing for point‑cloud clustering and tracking"
    DTDFVocab:enables ComputationOffloadingService
]

// C6: Services offered by the Digital Twin
instance DataMonitoringService : DTDFVocab:Service [
    base:desc "User interface displaying real‑time vehicle state, projected path, and nearby object tracks"
    DTDFVocab:provides VehicleStateInsight, ObjectTracksInsight
]

instance ComputationOffloadingService : DTDFVocab:Service [
    base:desc "Offloads ACC algorithm to cloud resources and returns desired speed set‑point for actuation"
    DTDFVocab:provides AdjustSpeedSetpointAction
]

instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Allows operators to enable/disable ACC, set desired speed, and issue emergency‑brake commands remotely"
    DTDFVocab:provides EmergencyBrakeAction
]

// C17: Insights and Actions generated by services
instance VehicleStateInsight : DTDFVocab:Insight [
    base:desc "Provides current ego‑vehicle state including speed, position, and heading"
]

instance ObjectTracksInsight : DTDFVocab:Insight [
    base:desc "Supplies tracked object data generated by point‑cloud clustering and Kalman‑filter tracking"
]

instance AdjustSpeedSetpointAction : DTDFVocab:Action [
    base:desc "Sets the vehicle's desired speed set‑point based on ACC calculations"
    DTDFVocab:IsAutomatic true
]

instance EmergencyBrakeAction : DTDFVocab:Action [
    base:desc "Issues an emergency brake command to stop the vehicle immediately"
    DTDFVocab:IsAutomatic false
]

// C10: Models / Algorithms
instance PointCloudClusteringTrackingModel : DTDFVocab:Model [
    base:desc "Clusters raw LiDAR point clouds using DBSCAN and tracks objects with a Kalman filter"
    DTDFVocab:inputTo NVIDIAJetpackGPUEnabler
]

instance AdaptiveCruiseControlModel : DTDFVocab:Model [
    base:desc "Consumes tracked object data and ego‑vehicle state to compute speed set‑points for ACC"
    DTDFVocab:inputTo CloudACCComputeEnabler
]

